arguments.argument:
if image_alpha=0.75 {image_alpha=0.25}
else {image_alpha=0.75}

//set in the instance creation code
switchCount=swAmount
for(i=0;i<swAmount;i+=1)
{
  if switchID[i].activated=1
    switchCount-=1
}
if switchCount<=0
{
  for(i=0;i<swAmount;i+=1)
    switchID[i].activated=2
  instance_destroy()
}
